import Link from "next/link";

import { getServerLanguage } from "@/lib/server-language";
import {
  getAccountOverview,
  requireAuthenticatedUser,
} from "@/lib/storefront-data";
import { formatIQD, getMessages } from "@/lib/storefront";

export const dynamic = "force-dynamic";

export default async function AccountPage() {
  const language = await getServerLanguage();
  const messages = getMessages(language);
  const { user } = await requireAuthenticatedUser();
  const { profile, orders, addresses } = await getAccountOverview(user.id);

  return (
    <div className="space-y-6">
      <section className="section-shell">
        <div className={language === "ar" ? "text-right" : "text-left"}>
          <p className="text-sm font-semibold text-primary">
            {messages.account.subtitle}
          </p>
          <h1 className="section-title">{messages.account.title}</h1>
        </div>
      </section>

      <div className="grid gap-6 lg:grid-cols-[0.95fr_1.05fr]">
        <section className="surface-card p-6">
          <h2 className="text-lg font-semibold text-slate-900">
            {messages.account.profile}
          </h2>
          <div className="mt-5 grid gap-4 text-sm text-slate-600">
            <div>
              <p className="text-xs uppercase tracking-[0.22em] text-primary/70">
                {messages.auth.fullName}
              </p>
              <p className="mt-1 font-medium text-slate-900">
                {profile?.full_name || user.user_metadata.full_name || "—"}
              </p>
            </div>
            <div>
              <p className="text-xs uppercase tracking-[0.22em] text-primary/70">
                {messages.auth.email}
              </p>
              <p className="mt-1 font-medium text-slate-900">{user.email || "—"}</p>
            </div>
            <div>
              <p className="text-xs uppercase tracking-[0.22em] text-primary/70">
                {messages.auth.phone}
              </p>
              <p className="mt-1 font-medium text-slate-900">
                {profile?.phone || user.user_metadata.phone || "—"}
              </p>
            </div>
          </div>
        </section>

        <section className="surface-card p-6">
          <div className="mb-5 flex items-center justify-between gap-3">
            <h2 className="text-lg font-semibold text-slate-900">
              {messages.account.recentOrders}
            </h2>
            <Link
              href="/account/orders"
              className="text-sm font-semibold text-primary transition hover:text-[#256a2a]"
            >
              {messages.account.allOrders}
            </Link>
          </div>

          {orders.length > 0 ? (
            <div className="grid gap-3">
              {orders.map((order) => (
                <Link
                  key={order.id}
                  href={`/account/orders/${order.id}`}
                  className="rounded-[1.75rem] border border-emerald-100 bg-[#f7fbf7] px-4 py-4 transition hover:border-primary"
                >
                  <div className="flex items-center justify-between gap-3">
                    <div>
                      <p className="text-sm font-semibold text-slate-900">
                        #{order.id.slice(0, 8)}
                      </p>
                      <p className="mt-1 text-xs text-slate-500">
                        {new Date(order.created_at).toLocaleDateString(
                          language === "ar" ? "ar-IQ" : "en-US"
                        )}
                      </p>
                    </div>
                    <div className="text-right">
                      <p className="text-sm font-semibold text-primary">
                        {formatIQD(order.total_iqd, language)}
                      </p>
                      <p className="mt-1 text-xs text-slate-500">{order.status}</p>
                    </div>
                  </div>
                </Link>
              ))}
            </div>
          ) : (
            <p className="rounded-[1.75rem] border border-dashed border-emerald-100 bg-[#f7fbf7] px-5 py-6 text-sm text-slate-500">
              {messages.account.noOrders}
            </p>
          )}
        </section>
      </div>

      <section className="surface-card p-6">
        <h2 className="text-lg font-semibold text-slate-900">
          {messages.account.savedAddresses}
        </h2>
        {addresses.length > 0 ? (
          <div className="mt-5 grid gap-3 sm:grid-cols-2">
            {addresses.map((address) => (
              <article
                key={address.id}
                className="rounded-[1.75rem] border border-emerald-100 bg-[#f7fbf7] px-5 py-4"
              >
                <p className="text-sm font-semibold text-slate-900">{address.name}</p>
                <p className="mt-2 text-sm text-slate-500">
                  {[address.city, address.area, address.street]
                    .filter(Boolean)
                    .join(", ")}
                </p>
                <p className="mt-2 text-sm text-slate-600">{address.phone}</p>
              </article>
            ))}
          </div>
        ) : (
          <p className="mt-5 rounded-[1.75rem] border border-dashed border-emerald-100 bg-[#f7fbf7] px-5 py-6 text-sm text-slate-500">
            {messages.account.noAddresses}
          </p>
        )}
      </section>
    </div>
  );
}
